input.new_str:
# Get active window
WINDOW=$(xdotool getactivewindow)

# Get window frame extents (decorations: left, right, top, bottom)
FRAME_EXTENTS=$(xprop -id "$WINDOW" _NET_FRAME_EXTENTS | awk '{print $3, $4, $5, $6}' | tr -d ',')
FRAME_LEFT=$(echo $FRAME_EXTENTS | awk '{print $1}')
FRAME_RIGHT=$(echo $FRAME_EXTENTS | awk '{print $2}')
FRAME_TOP=$(echo $FRAME_EXTENTS | awk '{print $3}')
FRAME_BOTTOM=$(echo $FRAME_EXTENTS | awk '{print $4}')

# If frame extents not available, use defaults
FRAME_LEFT=${FRAME_LEFT:-0}
FRAME_RIGHT=${FRAME_RIGHT:-0}
FRAME_TOP=${FRAME_TOP:-0}
FRAME_BOTTOM=${FRAME_BOTTOM:-0}
